        private static FilterResult ParseFilters(IQueryCollection query, HashSet<string> allowedColumns)
        {
            var clauses = new List<string>();
            var parameters = new List<SqlParameter>();
            int paramIndex = 0;

            // Reserved query string keys that are not filters
            var reservedKeys = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
            {
                "select", "sort", "sortDir", "page", "pageSize",
                "dateColumn", "dateFrom", "dateTo"
            };

            foreach (var key in query.Keys)
            {
                if (reservedKeys.Contains(key))
                    continue;

                // Parse filter format: column=value or column__operator=value
                string columnName;
                string operatorName = "eq";

                if (key.Contains("__"))
                {
                    var parts = key.Split("__", 2);
                    columnName = parts[0];
                    operatorName = parts[1];
                }
                else
                {
                    columnName = key;
                }

                // Validate column name
                if (!allowedColumns.Contains(columnName))
                {
                    return new FilterResult
                    {
                        Error = $"Invalid filter column: '{columnName}'. Allowed columns: {string.Join(", ", allowedColumns)}"
                    };
                }

                // Validate operator
                if (!AllowedOperators.Contains(operatorName))
                {
                    return new FilterResult
                    {
                        Error = $"Invalid operator: '{operatorName}'. Allowed operators: {string.Join(", ", AllowedOperators)}"
                    };
                }

                string resolvedColumn = allowedColumns.First(c => c.Equals(columnName, StringComparison.OrdinalIgnoreCase));
                string value = query[key];

                // Use bracket-quoted column names for safety (though they're already whitelisted)
                string quotedColumn = $"[{resolvedColumn}]";

                if (operatorName.Equals("in", StringComparison.OrdinalIgnoreCase))
                {
                    // Handle IN operator with multiple values
                    var values = value.Split(',', StringSplitOptions.RemoveEmptyEntries);
                    if (values.Length == 0)
                    {
                        return new FilterResult { Error = $"IN operator requires at least one value for column '{resolvedColumn}'" };
                    }

                    var inParams = new List<string>();
                    foreach (var v in values)
                    {
                        string paramName = $"@p{paramIndex++}";
                        inParams.Add(paramName);
                        parameters.Add(new SqlParameter(paramName, v.Trim()));
                    }
                    clauses.Add($"{quotedColumn} IN ({string.Join(", ", inParams)})");
                }
                else
                {
                    string paramName = $"@p{paramIndex++}";
                    string sqlOperator = MapOperator(operatorName);

                    if (operatorName.Equals("like", StringComparison.OrdinalIgnoreCase))
                    {
                        clauses.Add($"{quotedColumn} LIKE {paramName}");
                        parameters.Add(new SqlParameter(paramName, $"%{EscapeLikePattern(value)}%"));
                    }
                    else
                    {
                        clauses.Add($"{quotedColumn} {sqlOperator} {paramName}");
                        parameters.Add(new SqlParameter(paramName, value));
                    }
                }
            }

            return new FilterResult
            {
                FilterClauses = clauses,
                Parameters = parameters
            };
        }

        private static SelectResult ParseSelectColumns(string selectParam, HashSet<string> allowedColumns)
        {
            if (string.IsNullOrWhiteSpace(selectParam))
            {
                return new SelectResult { Columns = allowedColumns.ToList() };
            }

            var requestedColumns = selectParam.Split(',', StringSplitOptions.RemoveEmptyEntries)
                .Select(c => c.Trim())
                .ToList();

            var validatedColumns = new List<string>();
            foreach (var col in requestedColumns)
            {
                if (!allowedColumns.Contains(col))
                {
                    return new SelectResult
                    {
                        Error = $"Invalid select column: '{col}'. Allowed columns: {string.Join(", ", allowedColumns)}"
                    };
                }
                validatedColumns.Add(allowedColumns.First(c => c.Equals(col, StringComparison.OrdinalIgnoreCase)));
            }

            return new SelectResult { Columns = validatedColumns };
        }

        private static SortResult ParseSort(string sortColumn, string sortDirection, HashSet<string> allowedColumns)
        {
            string column = null;
            string direction = "ASC";

            if (!string.IsNullOrWhiteSpace(sortColumn))
            {
                if (!allowedColumns.Contains(sortColumn))
                {
                    return new SortResult
                    {
                        Error = $"Invalid sort column: '{sortColumn}'. Allowed columns: {string.Join(", ", allowedColumns)}"
                    };
                }
                column = allowedColumns.First(c => c.Equals(sortColumn, StringComparison.OrdinalIgnoreCase));
            }

            if (!string.IsNullOrWhiteSpace(sortDirection))
            {
                if (!AllowedSortDirections.Contains(sortDirection))
                {
                    return new SortResult { Error = "Invalid sort direction. Use 'ASC' or 'DESC'." };
                }
                direction = sortDirection.ToUpperInvariant();
            }

            return new SortResult { Column = column, Direction = direction };
        }

        private static DateRangeResult ParseDateRange(IQueryCollection query, HashSet<string> allowedColumns)
        {
            var clauses = new List<string>();
            var parameters = new List<SqlParameter>();

            string dateColumn = query["dateColumn"];
            string dateFrom = query["dateFrom"];
            string dateTo = query["dateTo"];

            if (string.IsNullOrWhiteSpace(dateColumn))
            {
                return new DateRangeResult { FilterClauses = clauses, Parameters = parameters };
            }

            if (!allowedColumns.Contains(dateColumn))
            {
                return new DateRangeResult
                {
                    Error = $"Invalid date column: '{dateColumn}'. Allowed columns: {string.Join(", ", allowedColumns)}"
                };
            }

            string resolvedColumn = allowedColumns.First(c => c.Equals(dateColumn, StringComparison.OrdinalIgnoreCase));
            string quotedColumn = $"[{resolvedColumn}]";

            if (!string.IsNullOrWhiteSpace(dateFrom))
            {
                if (!DateTime.TryParse(dateFrom, out DateTime fromDate))
                {
                    return new DateRangeResult { Error = $"Invalid dateFrom value: '{dateFrom}'. Use ISO 8601 format." };
                }
                clauses.Add($"{quotedColumn} >= @dateFrom");
                parameters.Add(new SqlParameter("@dateFrom", SqlDbType.DateTime2) { Value = fromDate });
            }

            if (!string.IsNullOrWhiteSpace(dateTo))
            {
                if (!DateTime.TryParse(dateTo, out DateTime toDate))
                {
                    return new DateRangeResult { Error = $"Invalid dateTo value: '{dateTo}'. Use ISO 8601 format." };
                }
                clauses.Add($"{quotedColumn} <= @dateTo");
                parameters.Add(new SqlParameter("@dateTo", SqlDbType.DateTime2) { Value = toDate });
            }

            return new DateRangeResult { FilterClauses = clauses, Parameters = parameters };
        }

        private static QueryBuildResult BuildParameterizedQuery(
            string tableName,
            List<string> selectColumns,
            List<string> filterClauses,
            List<SqlParameter> filterParams,
            List<string> dateFilterClauses,
            List<SqlParameter> dateFilterParams,
            string sortColumn,
            string sortDirection,
            int pageSize,
            int offset)
        {
            // Build SELECT clause with bracket-quoted column names
            string selectClause = string.Join(", ", selectColumns.Select(c => $"[{c}]"));

            // Combine all WHERE clauses
            var allClauses = new List<string>();
            allClauses.AddRange(filterClauses);
            allClauses.AddRange(dateFilterClauses);

            string whereClause = allClauses.Count > 0
                ? "WHERE " + string.Join(" AND ", allClauses)
                : "";

            // Build ORDER BY
            string orderByClause;
            if (!string.IsNullOrEmpty(sortColumn))
            {
                orderByClause = $"ORDER BY [{sortColumn}] {sortDirection}";
            }
            else
            {
                // Default sort by first column for consistent pagination
                orderByClause = $"ORDER BY [{selectColumns[0]}] ASC";
            }

            // Build the full query with pagination
            string sql = $@"
                SELECT {selectClause}
                FROM [{tableName}]
                {whereClause}
                {orderByClause}
                OFFSET @offset ROWS FETCH NEXT @pageSize ROWS ONLY";

            string countSql = $@"
                SELECT COUNT(*)
                FROM [{tableName}]
                {whereClause}";

            // Combine all parameters
            var allParams = new List<SqlParameter>();
            allParams.AddRange(filterParams);
            allParams.AddRange(dateFilterParams);

            return new QueryBuildResult
            {
                Sql = sql,
                CountSql = countSql,
                Parameters = allParams
            };
        }

        private static async Task<List<Dictionary<string, object>>> ExecuteQueryAsync(
            string connectionString,
            string sql,
            List<SqlParameter> parameters,
            ILogger log)
        {
            var results = new List<Dictionary<string, object>>();

            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();

                using (var command = new SqlCommand(sql, connection))
                {
                    command.CommandTimeout = 30;

                    // Add filter parameters
                    foreach (var param in parameters)
                    {
                        command.Parameters.Add(CloneSqlParameter(param));
                    }

                    // Add pagination parameters
                    command.Parameters.Add(new SqlParameter("@offset", SqlDbType.Int) { Value = 0 });
                    command.Parameters.Add(new SqlParameter("@pageSize", SqlDbType.Int) { Value = 100 });

                    // Override with actual values from the SQL (parsed from method params)
                    // We need to extract offset and pageSize - let's fix this by passing them
                    // Actually they're embedded in the SQL via parameter names, let's set them properly

                    using (var reader = await command.ExecuteReaderAsync())
                    {
                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                var value = reader.GetValue(i);
                                row[reader.GetName(i)] = value == DBNull.Value ? null : value;
                            }
                            results.Add(row);
                        }
                    }
                }
            }

            return results;
        }

        private static async Task<int> ExecuteCountQueryAsync(
            string connectionString,
            string countSql,
            List<SqlParameter> parameters,
            ILogger log)
        {
            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();

                using (var command = new SqlCommand(countSql, connection))
                {
                    command.CommandTimeout = 30;

                    foreach (var param in parameters)
                    {
                        command.Parameters.Add(CloneSqlParameter(param));
                    }

                    var result = await command.ExecuteScalarAsync();
                    return Convert.ToInt32(result);
                }
            }
        }

        // SqlParameters cannot be reused across commands, so we clone them
        private static SqlParameter CloneSqlParameter(SqlParameter source)
        {
            return new SqlParameter
            {
                ParameterName = source.ParameterName,
                SqlDbType = source.SqlDbType,
                Value = source.Value ?? DBNull.Value,
                Direction = source.Direction,
                Size = source.Size
            };
        }

        private static string MapOperator(string op)
        {
            return op.ToLowerInvariant() switch
            {
                "eq" => "=",
                "neq" => "!=",
                "gt" => ">",
                "gte" => ">=",
                "lt" => "<",
                "lte" => "<=",
                _ => "="
            };
        }

        private static string EscapeLikePattern(string input)
        {
            return input
                .Replace("[", "[[]")
                .Replace("%", "[%]")
                .Replace("_", "[_]");
        }

        private static int ParseInt(string value, int defaultValue, int min, int max)
        {
            if (int.TryParse(value, out int result))
            {
                return Math.Clamp(result, min, max);
            }
            return defaultValue;
        }

